import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => '{}'),
  mkdirSync: vi.fn(),
}));

const { atomicWriteMock } = vi.hoisted(() => ({ atomicWriteMock: vi.fn() }));
vi.mock('../../lib/atomic-write.js', () => ({
  atomicWriteSync: atomicWriteMock,
}));

import { existsSync, readFileSync } from 'node:fs';
import {
  loadAccumState,
  loadAccumStateOrNull,
  saveAccumState,
  evaluateCacheHeat,
  isInImminentZone,
  getCacheHotThreshold,
  getStateFile,
} from '../../lib/session-token-accum.js';

const ENV_KEYS = [
  'CLAUDE_MAX_CONTEXT',
  'ORK_CACHE_HOT_THRESHOLD',
  'ORK_NO_CACHE_AWARENESS',
  'ORK_CTX_IMMINENT_PCT',
];
function clearEnv() {
  for (const k of ENV_KEYS) delete process.env[k];
}

describe('session-token-accum', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    atomicWriteMock.mockClear();
    clearEnv();
  });
  afterEach(() => clearEnv());

  describe('getStateFile', () => {
    it('formats path under .claude/state', () => {
      const p = getStateFile('/proj', 'sess-A');
      expect(p).toContain('.claude/state/session-sess-A-token-accum.json');
    });
  });

  describe('loadAccumState', () => {
    it('returns fresh state when file missing', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      const s = loadAccumState('/proj', 'sess-A');
      expect(s.estimatedTokens).toBe(0);
      expect(s.cacheReadTokens).toBe(0);
      expect(s.cacheCreationTokens).toBe(0);
      expect(s.crossings).toEqual({});
      expect(s.firstSeenAt).toBeDefined();
    });

    it('loads + coerces partial state', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({ estimatedTokens: 1000, cacheReadTokens: 500 }),
      );
      const s = loadAccumState('/proj', 'sess-A');
      expect(s.estimatedTokens).toBe(1000);
      expect(s.cacheReadTokens).toBe(500);
      expect(s.cacheCreationTokens).toBe(0);
      expect(s.crossings).toEqual({});
    });

    it('returns fresh on corrupt JSON', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue('not json');
      const s = loadAccumState('/proj', 'sess-A');
      expect(s.estimatedTokens).toBe(0);
    });
  });

  describe('loadAccumStateOrNull', () => {
    it('returns null on empty/fresh state (no signal)', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      expect(loadAccumStateOrNull('/proj', 'sess-A')).toBeNull();
    });

    it('returns state when accumulator has data', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(JSON.stringify({ estimatedTokens: 50_000 }));
      expect(loadAccumStateOrNull('/proj', 'sess-A')?.estimatedTokens).toBe(50_000);
    });
  });

  describe('saveAccumState', () => {
    it('writes via atomicWriteSync', () => {
      saveAccumState('/proj', 'sess-A', {
        estimatedTokens: 1,
        cacheReadTokens: 0,
        cacheCreationTokens: 0,
        crossings: {},
        firstSeenAt: '2026-04-26T00:00:00.000Z',
        updatedAt: '2026-04-26T00:00:00.000Z',
      });
      expect(atomicWriteMock).toHaveBeenCalled();
    });
  });

  describe('getCacheHotThreshold', () => {
    it('defaults to 50000', () => {
      expect(getCacheHotThreshold()).toBe(50_000);
    });
    it('honours ORK_CACHE_HOT_THRESHOLD', () => {
      process.env.ORK_CACHE_HOT_THRESHOLD = '100000';
      expect(getCacheHotThreshold()).toBe(100_000);
    });
    it('rejects invalid values', () => {
      process.env.ORK_CACHE_HOT_THRESHOLD = 'foo';
      expect(getCacheHotThreshold()).toBe(50_000);
    });
  });

  describe('evaluateCacheHeat', () => {
    const longAgo = new Date(Date.now() - 60 * 60_000).toISOString();
    const recent = new Date().toISOString();

    it('returns hot when cache reads exceed threshold and session is mature', () => {
      const heat = evaluateCacheHeat({
        estimatedTokens: 1,
        cacheReadTokens: 80_000,
        cacheCreationTokens: 10_000,
        crossings: {},
        firstSeenAt: longAgo,
        updatedAt: recent,
      });
      expect(heat).toBe('hot');
    });

    it('returns neutral when session is short (< 30 min)', () => {
      const start = new Date(Date.now() - 5 * 60_000).toISOString();
      const heat = evaluateCacheHeat({
        estimatedTokens: 1,
        cacheReadTokens: 200_000,
        cacheCreationTokens: 0,
        crossings: {},
        firstSeenAt: start,
        updatedAt: recent,
      });
      expect(heat).toBe('neutral');
    });

    it('returns neutral when cache reads under threshold', () => {
      const heat = evaluateCacheHeat({
        estimatedTokens: 1,
        cacheReadTokens: 1000,
        cacheCreationTokens: 0,
        crossings: {},
        firstSeenAt: longAgo,
        updatedAt: recent,
      });
      expect(heat).toBe('neutral');
    });

    it('forces neutral when ORK_NO_CACHE_AWARENESS=1', () => {
      process.env.ORK_NO_CACHE_AWARENESS = '1';
      const heat = evaluateCacheHeat({
        estimatedTokens: 1,
        cacheReadTokens: 1_000_000,
        cacheCreationTokens: 0,
        crossings: {},
        firstSeenAt: longAgo,
        updatedAt: recent,
      });
      expect(heat).toBe('neutral');
    });
  });

  describe('isInImminentZone', () => {
    it('returns false for null state', () => {
      expect(isInImminentZone(null)).toBe(false);
    });

    it('returns true at imminent threshold (85% of 200k = 170k)', () => {
      process.env.CLAUDE_MAX_CONTEXT = '200000';
      expect(
        isInImminentZone({
          estimatedTokens: 170_000,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          crossings: {},
          firstSeenAt: '',
          updatedAt: '',
        }),
      ).toBe(true);
    });

    it('returns false below threshold', () => {
      process.env.CLAUDE_MAX_CONTEXT = '200000';
      expect(
        isInImminentZone({
          estimatedTokens: 100_000,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          crossings: {},
          firstSeenAt: '',
          updatedAt: '',
        }),
      ).toBe(false);
    });

    it('honours ORK_CTX_IMMINENT_PCT', () => {
      process.env.CLAUDE_MAX_CONTEXT = '200000';
      process.env.ORK_CTX_IMMINENT_PCT = '0.50';
      expect(
        isInImminentZone({
          estimatedTokens: 100_000,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          crossings: {},
          firstSeenAt: '',
          updatedAt: '',
        }),
      ).toBe(true);
    });
  });
});
